export const openDocsCommand = defineCommand({
	help: {
		commandName: 'astro docs',
		tables: {
			Flags: [['--help (-h)', 'See all available flags.']],
		},
		description: `Launches the Astro Docs website directly from the terminal.`,
	},
	async run({ url, operatingSystemProvider, logger, commandExecutor, cloudIdeProvider }: Options) {
		const platform = cloudIdeProvider.name ?? operatingSystemProvider.name;
		const input = getExecInputForPlatform(platform);
		if (!input) {
			logger.error(
				'SKIP_FORMAT',
				`It looks like your platform ("${platform}") isn't supported!\nTo view Astro's docs, please visit ${url}`,
			);
			return;
		}
		const [command, args = []] = input;
		await commandExecutor.execute(command, [...args, encodeURI(url)]);
	},
});

try {
	const i18nDir = new URL('content/i18n/', srcDir);
	// Load the user’s i18n directory
	const files = fs.readdirSync(i18nDir, 'utf-8');
	// Load the user’s i18n collection and ignore the error if it doesn’t exist.
	for (const file of files) {
		const filePath = path.parse(file);
		if (!contentCollectionFileExtensions.includes(filePath.ext)) continue;
		const id = filePath.name;
		const url = new URL(filePath.base, i18nDir);
		const content = fs.readFileSync(new URL(file, i18nDir), 'utf-8');
		const data = (
			filePath.ext === '.json'
				? JSON.parse(content)
				: yaml.load(content, { filename: fileURLToPath(url) })
		) as i18nSchemaOutput;
		userTranslations[id] = data;
	}
} catch (e: unknown) {
	if (e instanceof Error && 'code' in e && e.code === 'ENOENT') {
		// i18nDir doesn’t exist, so we ignore the error.
	} else {
		// Other errors may be meaningful, e.g. JSON syntax errors, so should be thrown.
		throw e;
	}
}
